        """Unary RPC - process a single data request."""
        start_ns = time.time_ns()
        
        try:
            result = self._processor.process(request.payload, request.data_type)
            self._requests_processed += 1
            
            processing_time = time.time_ns() - start_ns
            
            return datastream_pb2.DataResponse(
                request_id=request.request_id,
                result=result,
                status="SUCCESS",
                processing_time_ns=processing_time,
                metadata={"processor": request.data_type or "default"}
            )
        except Exception as e:
            logger.error(f"Error processing request {request.request_id}: {e}")
            context.set_code(grpc.StatusCode.INTERNAL)
