def create_server(
    host: str = "0.0.0.0",
    port: int = 50051,
    max_workers: int = None,
    use_so_reuseport: bool = True
) -> grpc.Server:
    """Create and configure a high-performance gRPC server."""
    
    if max_workers is None:
        import multiprocessing
        max_workers = max(multiprocessing.cpu_count() * 2, 8)
    
    logger.info(f"Configuring server with {max_workers} workers")
    
    # Thread pool for handling RPCs
    thread_pool = futures.ThreadPoolExecutor(
        max_workers=max_workers,
        thread_name_prefix="grpc-worker"
    )
    
    # Server options optimized for high throughput and low latency
    server_options = [
        # No message size limits
        ("grpc.max_send_message_length", -1),
        ("grpc.max_receive_message_length", -1),
        
        # No metadata size limits
        ("grpc.max_metadata_size", -1),
        
        # HTTP/2 tuning for high throughput
        ("grpc.http2.max_pings_without_data", 0),
        ("grpc.keepalive_time_ms", 10000),
        ("grpc.keepalive_timeout_ms", 5000),
        ("grpc.keepalive_permit_without_calls", 1),
        ("grpc.http2.min_time_between_pings_ms", 5000),
        ("grpc.http2.min_ping_interval_without_data_ms", 5000),
        
        # Large window sizes for high throughput streaming
        ("grpc.http2.max_frame_size", 16777215),  # Max allowed
        ("grpc.http2.stream_lookahead_bytes", 67108864),  # 64MB lookahead
        
        # Connection tuning
        ("grpc.max_concurrent_streams", 1000),
        ("grpc.http2.write_buffer_size", 8388608),  # 8MB write buffer
        
        # Enable SO_REUSEPORT for multi-process scaling
        ("grpc.so_reuseport", int(use_so_reuseport)),
        
        # Optimization flags
        ("grpc.optimization_target", "throughput"),
        
        # Large per-RPC buffer
        ("grpc.per_rpc_retry_buffer_size", 8388608),  # 8MB
    ]
    
    server = grpc.server(
        thread_pool,
        options=server_options,
        maximum_concurrent_rpcs=None,  # No limit on concurrent RPCs
        compression=grpc.Compression.NoCompression,  # Avoid compression overhead for low latency
    )
    
    # Register service
    servicer = DataStreamServicer()
    datastream_pb2_grpc.add_DataStreamServiceServicer_to_server(servicer, server)
    
    # Bind to address
    address = f"{host}:{port}"
    server.add_insecure_port(address)
    
    logger.info(f"Server configured to listen on {address}")
    
    return server, servicer


def serve(host: str = "0.0.0.0", port: int = 50051):
    """Start the gRPC server."""
    server, servicer = create_server(host=host, port=port)
    server.start()
    logger.info(f"gRPC server started on {host}:{port}")
    
    # Graceful shutdown handling
    shutdown_event = futures.Future()
    
    def shutdown_handler(signum, frame):
        logger.info(f"Received signal {signum}, initiating graceful shutdown...")
        shutdown_event.set_result(True)
    
    signal.signal(signal.SIGINT, shutdown_handler)
    signal.signal(signal.SIGTERM, shutdown_handler)
    
    try:
        shutdown_event.result()
    except Exception:
        pass
    
    logger.info("Shutting down server (5s grace period)...")
    stopped_event = server.stop(grace=5)
    stopped_event.wait()
    logger.info("Server stopped.")


